import EventEmitter from 'events';
import Log from '../utils/logger.js';
import Browser from '../utils/browser.js';
import MediaInfo from './media-info.js';
import FLVDemuxer from '../demux/flv-demuxer.js';
import TSDemuxer from '../demux/ts-demuxer';
import MP4Remuxer from '../remux/mp4-remuxer.js';
import DemuxErrors from '../demux/demux-errors.js';
import IOController from '../io/io-controller.js';
import TransmuxingEvents from './transmuxing-events';
import {LoaderStatus, LoaderErrors} from '../io/loader.js';

// Transmuxing (IO, Demuxing, Remuxing) controller, with multipart support
class TransmuxingController {

    constructor(mediaDataSource, config) {
        this.TAG = 'TransmuxingController';
        this._emitter = new EventEmitter();

        this._config = config;

        // treat single part media as multipart media, which has only one segment
        if (!mediaDataSource.segments) {
            mediaDataSource.segments = [{
                duration: mediaDataSource.duration,
                filesize: mediaDataSource.filesize,
                url: mediaDataSource.url
            }];
        }

        // fill in default IO params if not exists
        if (typeof mediaDataSource.cors !== 'boolean') {
            mediaDataSource.cors = true;
        }
        if (typeof mediaDataSource.withCredentials !== 'boolean') {
            mediaDataSource.withCredentials = false;
        }

        this._mediaDataSource = mediaDataSource;
        this._currentSegmentIndex = 0;
        let totalDuration = 0;

        this._mediaDataSource.segments.forEach((segment) => {
            // timestampBase for each segment, and calculate total duration
            segment.timestampBase = totalDuration;
            totalDuration += segment.duration;
            // params needed by IOController
            segment.cors = mediaDataSource.cors;
            segment.withCredentials = mediaDataSource.withCredentials;
            // referrer policy control, if exist
            if (config.referrerPolicy) {
                segment.referrerPolicy = config.referrerPolicy;
            }
        });

        if (!isNaN(totalDuration) && this._mediaDataSource.duration !== totalDuration) {
            this._mediaDataSource.duration = totalDuration;
        }

        this._mediaInfo = null;
        this._demuxer = null;
        this._remuxer = null;
        this._ioctl = null;

        this._pendingSeekTime = null;
        this._pendingResolveSeekPoint = null;

        this._statisticsReporter = null;

        // Intelligent probing state for unseekable media
        this._isProbing = false;
        this._probeTargetTime = null;
        this._probeAttempts = 0;
        this._probeCurrentOffset = 0;  // Track current probe offset
        this._probeTimeout = null;  // Timeout for probe fallback
        this._discoveredKeyframes = new Map();  // Map<timestamp, fileposition>
        this._probeHistory = [];  // Array of {timestamp, fileposition} for better estimation
        this._maxProbeAttempts = 10;  // Maximum number of probing iterations
        this._probeChunkSize = 1024 * 1024;  // 1MB per probe request (increased from 256KB)
    }

    destroy() {
        this._mediaInfo = null;
        this._mediaDataSource = null;

        if (this._statisticsReporter) {
            this._disableStatisticsReporter();
        }
        if (this._ioctl) {
            this._ioctl.destroy();
            this._ioctl = null;
        }
        if (this._demuxer) {
            this._demuxer.destroy();
            this._demuxer = null;
        }
        if (this._remuxer) {
            this._remuxer.destroy();
            this._remuxer = null;
        }

        this._discoveredKeyframes = null;
        this._probeHistory = null;

        if (this._probeTimeout) {
            clearTimeout(this._probeTimeout);
            this._probeTimeout = null;
        }

        this._emitter.removeAllListeners();
        this._emitter = null;
    }

    on(event, listener) {
        this._emitter.addListener(event, listener);
    }

    off(event, listener) {
        this._emitter.removeListener(event, listener);
    }

    start() {
        this._loadSegment(0);
        this._enableStatisticsReporter();
    }

    _loadSegment(segmentIndex, optionalFrom) {
        this._currentSegmentIndex = segmentIndex;
        let dataSource = this._mediaDataSource.segments[segmentIndex];

        let ioctl = this._ioctl = new IOController(dataSource, this._config, segmentIndex);
        ioctl.onError = this._onIOException.bind(this);
        ioctl.onSeeked = this._onIOSeeked.bind(this);
        ioctl.onComplete = this._onIOComplete.bind(this);
        ioctl.onRedirect = this._onIORedirect.bind(this);
        ioctl.onRecoveredEarlyEof = this._onIORecoveredEarlyEof.bind(this);

        if (optionalFrom) {
            this._demuxer.bindDataSource(this._ioctl);
        } else {
            ioctl.onDataArrival = this._onInitChunkArrival.bind(this);
        }

        ioctl.open(optionalFrom);
    }

    stop() {
        this._internalAbort();
        this._disableStatisticsReporter();
    }

    _internalAbort() {
        if (this._ioctl) {
            this._ioctl.destroy();
            this._ioctl = null;
        }
    }

    pause() {  // take a rest
        if (this._ioctl && this._ioctl.isWorking()) {
            this._ioctl.pause();
            this._disableStatisticsReporter();
        }
    }

    resume() {
        if (this._ioctl && this._ioctl.isPaused()) {
            this._ioctl.resume();
            this._enableStatisticsReporter();
        }
    }

    seek(milliseconds) {
        if (this._mediaInfo == null) {
            return;
        }

        // Check if media has index (normal seekable media)
        if (this._mediaInfo.isSeekable()) {
            Log.v(this.TAG, `Seeking to ${milliseconds}ms using indexed seek`);
            this._performIndexedSeek(milliseconds);
            return;
        }

        // Media is unseekable (no index), use intelligent probing
        Log.v(this.TAG, `Seeking to ${milliseconds}ms using intelligent probing (no index)`);
        this._performIntelligentSeek(milliseconds);
    }

    _performIndexedSeek(milliseconds) {
        let targetSegmentIndex = this._searchSegmentIndexContains(milliseconds);

        if (targetSegmentIndex === this._currentSegmentIndex) {
            // intra-segment seeking
            let segmentInfo = this._mediaInfo.segments[targetSegmentIndex];

            if (segmentInfo == undefined) {
                // current segment loading started, but mediainfo hasn't received yet
                // wait for the metadata loaded, then seek to expected position
                this._pendingSeekTime = milliseconds;
            } else {
                let keyframe = segmentInfo.getNearestKeyframe(milliseconds);
                this._remuxer.seek(keyframe.milliseconds);
                this._ioctl.seek(keyframe.fileposition);
                // Will be resolved in _onRemuxerMediaSegmentArrival()
                this._pendingResolveSeekPoint = keyframe.milliseconds;
            }
        } else {
            // cross-segment seeking
            let targetSegmentInfo = this._mediaInfo.segments[targetSegmentIndex];

            if (targetSegmentInfo == undefined) {
                // target segment hasn't been loaded. We need metadata then seek to expected time
                this._pendingSeekTime = milliseconds;
                this._internalAbort();
                this._remuxer.seek();
                this._remuxer.insertDiscontinuity();
                this._loadSegment(targetSegmentIndex);
                // Here we wait for the metadata loaded, then seek to expected position
            } else {
                // We have target segment's metadata, direct seek to target position
                let keyframe = targetSegmentInfo.getNearestKeyframe(milliseconds);
                this._internalAbort();
                this._remuxer.seek(milliseconds);
                this._remuxer.insertDiscontinuity();
                this._demuxer.resetMediaInfo();
                this._demuxer.timestampBase = this._mediaDataSource.segments[targetSegmentIndex].timestampBase;
                this._loadSegment(targetSegmentIndex, keyframe.fileposition);
                this._pendingResolveSeekPoint = keyframe.milliseconds;
                this._reportSegmentMediaInfo(targetSegmentIndex);
            }
        }

        this._enableStatisticsReporter();
    }

    _performIntelligentSeek(milliseconds) {
        // For unseekable media, check if we have a discovered keyframe nearby
        let nearestKeyframe = this._findNearestDiscoveredKeyframe(milliseconds);

        if (nearestKeyframe && Math.abs(nearestKeyframe.milliseconds - milliseconds) < 5000) {
            // Found a nearby keyframe (within 5 seconds), use it directly
            Log.i(this.TAG, `Using discovered keyframe at ${nearestKeyframe.milliseconds}ms for seek to ${milliseconds}ms`);
            this._internalAbort();
            this._remuxer.seek(nearestKeyframe.milliseconds);
            this._remuxer.insertDiscontinuity();
            this._loadSegment(this._currentSegmentIndex, nearestKeyframe.fileposition);
            this._pendingResolveSeekPoint = nearestKeyframe.milliseconds;
            this._enableStatisticsReporter();
        } else {
            // No nearby keyframe found, initiate intelligent probing
            Log.i(this.TAG, `Starting intelligent probing for seek to ${milliseconds}ms`);
            this._startProbing(milliseconds);
        }
    }

    _findNearestDiscoveredKeyframe(targetTime) {
        if (this._probeHistory.length === 0) {
            return null;
        }

        let nearest = null;
        let minDistance = Infinity;

        for (let entry of this._probeHistory) {
            let distance = Math.abs(entry.milliseconds - targetTime);
            if (distance < minDistance) {
                minDistance = distance;
                nearest = entry;
            }
        }

        return nearest;
    }

    _startProbing(targetTime) {
        if (this._isProbing) {
            Log.w(this.TAG, 'Already probing, ignoring new probe request');
            return;
        }

        this._isProbing = true;
        this._probeTargetTime = targetTime;
        this._probeAttempts = 0;

        // Emit buffering start event
        this._emitter.emit(TransmuxingEvents.BUFFERING_START);

        // Calculate initial estimate
        let estimatedOffset = this._estimateByteOffset(targetTime);
        this._probeCurrentOffset = estimatedOffset;
        Log.i(this.TAG, `Probing attempt 1: seeking to ${targetTime}ms, estimated offset: ${estimatedOffset}`);

        // Abort current downloads and start probing
        this._internalAbort();
        if (this._remuxer) {
            this._remuxer.seek();
            this._remuxer.insertDiscontinuity();
        }

        // Load from estimated offset
        this._loadSegment(this._currentSegmentIndex, estimatedOffset);
    }

    _estimateByteOffset(targetTime) {
        let duration = this._mediaDataSource.duration;
        let filesize = this._mediaDataSource.segments[this._currentSegmentIndex].filesize;

        // If we have no data points, use simple linear interpolation
        if (this._probeHistory.length === 0) {
            if (duration && filesize) {
                let ratio = targetTime / duration;
                return Math.floor(filesize * ratio);
            }
            // If duration is unknown, estimate based on typical bitrate assumptions
            // Assume ~2Mbps average bitrate for video
            if (filesize) {
                let estimatedDuration = (filesize * 8) / (2 * 1000 * 1000);  // seconds
                let ratio = (targetTime / 1000) / estimatedDuration;
                Log.v(this.TAG, `Duration unknown, estimating based on filesize. Estimated duration: ${estimatedDuration}s, seeking to ${targetTime/1000}s (${Math.round(ratio*100)}% of file)`);
                return Math.floor(filesize * Math.min(ratio, 0.95));  // Cap at 95% to avoid EOF
            }
            // Last resort fallback
            return Math.floor((filesize || 0) / 2);
        }

        // We have data points, use them for better estimation
        // Sort by timestamp
        let sorted = [...this._probeHistory].sort((a, b) => a.milliseconds - b.milliseconds);

        // Find two points that bracket the target time
        let before = null;
        let after = null;

        for (let i = 0; i < sorted.length; i++) {
            if (sorted[i].milliseconds <= targetTime) {
                before = sorted[i];
            }
            if (sorted[i].milliseconds >= targetTime && !after) {
                after = sorted[i];
            }
        }

        // If we have both bracketing points, interpolate
        if (before && after && before !== after) {
            let timeRange = after.milliseconds - before.milliseconds;
            let offsetRange = after.fileposition - before.fileposition;
            let timeOffset = targetTime - before.milliseconds;
            let ratio = timeOffset / timeRange;
            return Math.floor(before.fileposition + (offsetRange * ratio));
        }

        // If we only have one side, extrapolate
        if (before) {
            let filesize = this._mediaDataSource.segments[this._currentSegmentIndex].filesize;

            // Calculate bitrate from the known point
            let bytesPerMs = before.fileposition / before.milliseconds;
            let offset = before.fileposition + ((targetTime - before.milliseconds) * bytesPerMs);

            // If we have duration, use it to bound the estimate
            if (duration) {
                let remainingTime = duration - before.milliseconds;
                let remainingBytes = filesize - before.fileposition;
                let altBytesPerMs = remainingBytes / remainingTime;
                // Average the two estimates for better accuracy
                bytesPerMs = (bytesPerMs + altBytesPerMs) / 2;
                offset = before.fileposition + ((targetTime - before.milliseconds) * bytesPerMs);
            }

            return Math.floor(Math.max(0, Math.min(filesize, offset)));
        }

        if (after) {
            let timeFromStart = after.milliseconds;
            let bytesFromStart = after.fileposition;
            let bytesPerMs = bytesFromStart / timeFromStart;
            let offset = targetTime * bytesPerMs;
            let filesize = this._mediaDataSource.segments[this._currentSegmentIndex].filesize;
            return Math.floor(Math.max(0, Math.min(filesize, offset)));
        }

        // Fallback
        return 0;
    }

    _searchSegmentIndexContains(milliseconds) {
        let segments = this._mediaDataSource.segments;
        let idx = segments.length - 1;

        for (let i = 0; i < segments.length; i++) {
            if (milliseconds < segments[i].timestampBase) {
                idx = i - 1;
                break;
            }
        }
        return idx;
    }

    _onInitChunkArrival(data, byteStart) {
        let consumed = 0;

        if (byteStart > 0) {
            // IOController seeked immediately after opened, byteStart > 0 callback may received
            this._demuxer.bindDataSource(this._ioctl);
            this._demuxer.timestampBase = this._mediaDataSource.segments[this._currentSegmentIndex].timestampBase;

            consumed = this._demuxer.parseChunks(data, byteStart);
        } else {
            // byteStart == 0, Initial data, probe it first
            let probeData = null;

            // Try probing input data as FLV first
            probeData = FLVDemuxer.probe(data);
            if (probeData.match) {
                // Hit as FLV
                this._setupFLVDemuxerRemuxer(probeData);
                consumed = this._demuxer.parseChunks(data, byteStart);
            }

            if (!probeData.match && !probeData.needMoreData) {
                // Non-FLV, try MPEG-TS probe
                probeData = TSDemuxer.probe(data);
                if (probeData.match) {
                    // Hit as MPEG-TS
                    this._setupTSDemuxerRemuxer(probeData);
                    consumed = this._demuxer.parseChunks(data, byteStart);
                }
            }

            if (!probeData.match && !probeData.needMoreData) {
                // Both probing as FLV / MPEG-TS failed, report error
                probeData = null;
                Log.e(this.TAG, 'Non MPEG-TS/FLV, Unsupported media type!');
                Promise.resolve().then(() => {
                    this._internalAbort();
                });
                this._emitter.emit(TransmuxingEvents.DEMUX_ERROR, DemuxErrors.FORMAT_UNSUPPORTED, 'Non MPEG-TS/FLV, Unsupported media type!');
                // Leave consumed as 0
            }
        }

        return consumed;
    }

    _setupFLVDemuxerRemuxer(probeData) {
        this._demuxer = new FLVDemuxer(probeData, this._config);

        if (!this._remuxer) {
            this._remuxer = new MP4Remuxer(this._config);
        }

        let mds = this._mediaDataSource;
        if (mds.duration != undefined && !isNaN(mds.duration)) {
            this._demuxer.overridedDuration = mds.duration;
        }
        if (typeof mds.hasAudio === 'boolean') {
            this._demuxer.overridedHasAudio = mds.hasAudio;
        }
        if (typeof mds.hasVideo === 'boolean') {
            this._demuxer.overridedHasVideo = mds.hasVideo;
        }

        this._demuxer.timestampBase = mds.segments[this._currentSegmentIndex].timestampBase;

        this._demuxer.onError = this._onDemuxException.bind(this);
        this._demuxer.onMediaInfo = this._onMediaInfo.bind(this);
        this._demuxer.onMetaDataArrived = this._onMetaDataArrived.bind(this);
        this._demuxer.onScriptDataArrived = this._onScriptDataArrived.bind(this);

        this._remuxer.bindDataSource(this._demuxer
                        .bindDataSource(this._ioctl
        ));

        this._remuxer.onInitSegment = this._onRemuxerInitSegmentArrival.bind(this);
        this._remuxer.onMediaSegment = this._onRemuxerMediaSegmentArrival.bind(this);
    }

    _setupTSDemuxerRemuxer(probeData) {
        let demuxer = this._demuxer = new TSDemuxer(probeData, this._config);

        if (!this._remuxer) {
            this._remuxer = new MP4Remuxer(this._config);
        }

        demuxer.onError = this._onDemuxException.bind(this);
        demuxer.onMediaInfo = this._onMediaInfo.bind(this);
        demuxer.onMetaDataArrived = this._onMetaDataArrived.bind(this);
        demuxer.onTimedID3Metadata = this._onTimedID3Metadata.bind(this);
        demuxer.onPGSSubtitleData = this._onPGSSubtitle.bind(this);
        demuxer.onSynchronousKLVMetadata = this._onSynchronousKLVMetadata.bind(this);
        demuxer.onAsynchronousKLVMetadata = this._onAsynchronousKLVMetadata.bind(this);
        demuxer.onSMPTE2038Metadata = this._onSMPTE2038Metadata.bind(this);
        demuxer.onSCTE35Metadata = this._onSCTE35Metadata.bind(this);
        demuxer.onPESPrivateDataDescriptor = this._onPESPrivateDataDescriptor.bind(this);
        demuxer.onPESPrivateData = this._onPESPrivateData.bind(this);

        this._remuxer.bindDataSource(this._demuxer);
        this._demuxer.bindDataSource(this._ioctl);

        this._remuxer.onInitSegment = this._onRemuxerInitSegmentArrival.bind(this);
        this._remuxer.onMediaSegment = this._onRemuxerMediaSegmentArrival.bind(this);
    }

    _onMediaInfo(mediaInfo) {
        if (this._mediaInfo == null) {
            // Store first segment's mediainfo as global mediaInfo
            this._mediaInfo = Object.assign({}, mediaInfo);
            this._mediaInfo.keyframesIndex = null;
            this._mediaInfo.segments = [];
            this._mediaInfo.segmentCount = this._mediaDataSource.segments.length;
            Object.setPrototypeOf(this._mediaInfo, MediaInfo.prototype);

            // Log seekability info
            Log.i(this.TAG, `Media info received - hasKeyframesIndex: ${mediaInfo.hasKeyframesIndex}, isSeekable: ${this._mediaInfo.isSeekable()}`);
        }

        let segmentInfo = Object.assign({}, mediaInfo);
        Object.setPrototypeOf(segmentInfo, MediaInfo.prototype);
        this._mediaInfo.segments[this._currentSegmentIndex] = segmentInfo;

        // notify mediaInfo update
        this._reportSegmentMediaInfo(this._currentSegmentIndex);

        if (this._pendingSeekTime != null) {
            Promise.resolve().then(() => {
                let target = this._pendingSeekTime;
                this._pendingSeekTime = null;
                this.seek(target);
            });
        }
    }

    _onMetaDataArrived(metadata) {
        this._emitter.emit(TransmuxingEvents.METADATA_ARRIVED, metadata);
    }

    _onScriptDataArrived(data) {
        this._emitter.emit(TransmuxingEvents.SCRIPTDATA_ARRIVED, data);
    }

    _onTimedID3Metadata(timed_id3_metadata) {
        let timestamp_base = this._remuxer.getTimestampBase();
        if (timestamp_base == undefined) { return; }

        if (timed_id3_metadata.pts != undefined) {
            timed_id3_metadata.pts -= timestamp_base;
        }

        if (timed_id3_metadata.dts != undefined) {
            timed_id3_metadata.dts -= timestamp_base;
        }

        this._emitter.emit(TransmuxingEvents.TIMED_ID3_METADATA_ARRIVED, timed_id3_metadata);
    }

    _onPGSSubtitle(pgs_data) {
        let timestamp_base = this._remuxer.getTimestampBase();
        if (timestamp_base == undefined) { return; }

        if (pgs_data.pts != undefined) {
            pgs_data.pts -= timestamp_base;
        }

        if (pgs_data.dts != undefined) {
            pgs_data.dts -= timestamp_base;
        }

        this._emitter.emit(TransmuxingEvents.PGS_SUBTITLE_ARRIVED, pgs_data);
    }

    _onSynchronousKLVMetadata(synchronous_klv_metadata) {
        let timestamp_base = this._remuxer.getTimestampBase();
        if (timestamp_base == undefined) { return; }

        if (synchronous_klv_metadata.pts != undefined) {
            synchronous_klv_metadata.pts -= timestamp_base;
        }

        if (synchronous_klv_metadata.dts != undefined) {
            synchronous_klv_metadata.dts -= timestamp_base;
        }

        this._emitter.emit(TransmuxingEvents.SYNCHRONOUS_KLV_METADATA_ARRIVED, synchronous_klv_metadata);
    }

    _onAsynchronousKLVMetadata(asynchronous_klv_metadata) {
        this._emitter.emit(TransmuxingEvents.ASYNCHRONOUS_KLV_METADATA_ARRIVED, asynchronous_klv_metadata);
    }

    _onSMPTE2038Metadata(smpte2038_metadata) {
        let timestamp_base = this._remuxer.getTimestampBase();
        if (timestamp_base == undefined) { return; }

        if (smpte2038_metadata.pts != undefined) {
            smpte2038_metadata.pts -= timestamp_base;
        }

        if (smpte2038_metadata.dts != undefined) {
            smpte2038_metadata.dts -= timestamp_base;
        }

        if (smpte2038_metadata.nearest_pts != undefined) {
            smpte2038_metadata.nearest_pts -= timestamp_base;
        }

        this._emitter.emit(TransmuxingEvents.SMPTE2038_METADATA_ARRIVED, smpte2038_metadata);
    }

    _onSCTE35Metadata(scte35) {
        let timestamp_base = this._remuxer.getTimestampBase();
        if (timestamp_base == undefined) { return; }

        if (scte35.pts != undefined) {
            scte35.pts -= timestamp_base;
        }

        if (scte35.nearest_pts != undefined) {
            scte35.nearest_pts -= timestamp_base;
        }

        this._emitter.emit(TransmuxingEvents.SCTE35_METADATA_ARRIVED, scte35);
    }

    _onPESPrivateDataDescriptor(descriptor) {
        this._emitter.emit(TransmuxingEvents.PES_PRIVATE_DATA_DESCRIPTOR, descriptor);
    }

    _onPESPrivateData(private_data) {
        let timestamp_base = this._remuxer.getTimestampBase();
        if (timestamp_base == undefined) { return; }

        if (private_data.pts != undefined) {
            private_data.pts -= timestamp_base;
        }

        if (private_data.nearest_pts != undefined) {
            private_data.nearest_pts -= timestamp_base;
        }

        if (private_data.dts != undefined) {
            private_data.dts -= timestamp_base;
        }

        this._emitter.emit(TransmuxingEvents.PES_PRIVATE_DATA_ARRIVED, private_data);
    }

    _onIOSeeked() {
        this._remuxer.insertDiscontinuity();
    }

    _onIOComplete(extraData) {
        // If we're probing, the IO completion just means the probe chunk finished loading
        // Don't emit LOADING_COMPLETE, just wait for the probe analysis
        if (this._isProbing) {
            Log.v(this.TAG, `IO complete during probing (loaded probe chunk), waiting for media segments`);
            // If no media segments arrived yet, the probe chunk might not have contained a keyframe
            // Give it a moment, then check if we need to try a different offset
            if (this._probeTimeout) {
                clearTimeout(this._probeTimeout);
            }
            this._probeTimeout = setTimeout(() => {
                if (this._isProbing) {
                    Log.w(this.TAG, `No video segments received after probe chunk loaded, trying next probe`);
                    // Increment attempts and try again with a slightly different offset
                    this._probeAttempts++;
                    if (this._probeAttempts >= this._maxProbeAttempts) {
                        Log.e(this.TAG, `Probe failed after ${this._maxProbeAttempts} attempts with no video data`);
                        this._failProbing();
                    } else {
                        // Try probing a bit further ahead
                        let newOffset = this._probeCurrentOffset + this._probeChunkSize;
                        this._probeCurrentOffset = newOffset;
                        Log.i(this.TAG, `Probing again at offset ${newOffset}`);
                        this._internalAbort();
                        this._loadSegment(this._currentSegmentIndex, newOffset);
                    }
                }
            }, 500);  // Wait 500ms for media segments to arrive
            return;
        }

        let segmentIndex = extraData;
        let nextSegmentIndex = segmentIndex + 1;

        if (nextSegmentIndex < this._mediaDataSource.segments.length) {
            this._internalAbort();
            if (this._remuxer) {
                this._remuxer.flushStashedSamples();
            }
            this._loadSegment(nextSegmentIndex);
        } else {
            if (this._remuxer) {
                this._remuxer.flushStashedSamples();
            }
            this._emitter.emit(TransmuxingEvents.LOADING_COMPLETE);
            this._disableStatisticsReporter();
        }
    }

    _onIORedirect(redirectedURL) {
        let segmentIndex = this._ioctl.extraData;
        this._mediaDataSource.segments[segmentIndex].redirectedURL = redirectedURL;
    }

    _onIORecoveredEarlyEof() {
        this._emitter.emit(TransmuxingEvents.RECOVERED_EARLY_EOF);
    }

    _onIOException(type, info) {
        Log.e(this.TAG, `IOException: type = ${type}, code = ${info.code}, msg = ${info.msg}`);
        this._emitter.emit(TransmuxingEvents.IO_ERROR, type, info);
        this._disableStatisticsReporter();
    }

    _onDemuxException(type, info) {
        Log.e(this.TAG, `DemuxException: type = ${type}, info = ${info}`);
        this._emitter.emit(TransmuxingEvents.DEMUX_ERROR, type, info);
    }

    _onRemuxerInitSegmentArrival(type, initSegment) {
        this._emitter.emit(TransmuxingEvents.INIT_SEGMENT, type, initSegment);
    }

    _onRemuxerMediaSegmentArrival(type, mediaSegment) {
        // If we're in probing mode, handle the probe data instead of playing it
        if (this._isProbing) {
            if (type === 'video') {
                Log.v(this.TAG, `Received video media segment during probing`);
                this._handleProbeArrival(mediaSegment);
                return;
            } else {
                Log.v(this.TAG, `Received ${type} media segment during probing, ignoring`);
                return;  // Ignore audio segments during probing
            }
        }

        if (this._pendingSeekTime != null) {
            // Media segments after new-segment cross-seeking should be dropped.
            return;
        }
        this._emitter.emit(TransmuxingEvents.MEDIA_SEGMENT, type, mediaSegment);

        // Resolve pending seekPoint
        if (this._pendingResolveSeekPoint != null && type === 'video') {
            let syncPoints = mediaSegment.info.syncPoints;
            let seekpoint = this._pendingResolveSeekPoint;
            this._pendingResolveSeekPoint = null;

            // Safari: Pass PTS for recommend_seekpoint
            if (Browser.safari && syncPoints.length > 0 && syncPoints[0].originalDts === seekpoint) {
                seekpoint = syncPoints[0].pts;
            }
            // else: use original DTS (keyframe.milliseconds)

            this._emitter.emit(TransmuxingEvents.RECOMMEND_SEEKPOINT, seekpoint);
        }
    }

    _handleProbeArrival(mediaSegment) {
        // Clear the timeout since we received video data
        if (this._probeTimeout) {
            clearTimeout(this._probeTimeout);
            this._probeTimeout = null;
        }

        this._probeAttempts++;

        // Extract the first keyframe's timestamp and file position
        let syncPoints = mediaSegment.info.syncPoints;
        if (!syncPoints || syncPoints.length === 0) {
            Log.e(this.TAG, 'Probe failed: no sync points found');
            this._failProbing();
            return;
        }

        // Get the first keyframe's timestamp
        let firstKeyframe = syncPoints[0];
        let foundTimestamp = firstKeyframe.originalDts;
        let foundOffset = this._probeCurrentOffset;

        Log.i(this.TAG, `Probe attempt ${this._probeAttempts}: found timestamp ${foundTimestamp}ms at offset ${foundOffset}, target: ${this._probeTargetTime}ms`);

        // Store this discovery in our sparse index
        this._probeHistory.push({
            milliseconds: foundTimestamp,
            fileposition: foundOffset
        });

        // Check if we're close enough to the target (within 2 seconds)
        let timeDiff = Math.abs(foundTimestamp - this._probeTargetTime);
        if (timeDiff < 2000) {
            // Success! We found the right location
            Log.i(this.TAG, `Probe succeeded: found ${foundTimestamp}ms (target: ${this._probeTargetTime}ms, diff: ${timeDiff}ms)`);
            this._finishProbing(foundOffset, foundTimestamp);
            return;
        }

        // Check if we've exceeded max attempts
        if (this._probeAttempts >= this._maxProbeAttempts) {
            Log.w(this.TAG, `Probe failed: max attempts (${this._maxProbeAttempts}) reached. Using closest found position.`);
            this._finishProbing(foundOffset, foundTimestamp);
            return;
        }

        // Not close enough, calculate a better estimate and try again
        Log.i(this.TAG, `Probe miss (diff: ${timeDiff}ms), attempting correction...`);
        let newEstimate = this._estimateByteOffset(this._probeTargetTime);
        this._probeCurrentOffset = newEstimate;

        // Abort current download and start new probe
        this._internalAbort();
        this._loadSegment(this._currentSegmentIndex, newEstimate);
    }

    _finishProbing(finalOffset, finalTime) {
        Log.i(this.TAG, `Finishing probe at offset ${finalOffset}, time ${finalTime}ms`);

        // Clear probing state
        this._isProbing = false;
        this._probeTargetTime = null;
        this._probeAttempts = 0;

        if (this._probeTimeout) {
            clearTimeout(this._probeTimeout);
            this._probeTimeout = null;
        }

        // Emit buffering end event
        this._emitter.emit(TransmuxingEvents.BUFFERING_END);

        // Reset remuxer state to prepare for playback at the new position
        this._internalAbort();
        this._remuxer.seek(finalTime);
        this._remuxer.insertDiscontinuity();

        // Begin normal media loading for playback from the discovered position
        this._loadSegment(this._currentSegmentIndex, finalOffset);
        this._pendingResolveSeekPoint = finalTime;

        this._enableStatisticsReporter();
    }

    _failProbing() {
        Log.e(this.TAG, 'Probing failed, falling back to start of segment');
        this._isProbing = false;
        this._probeTargetTime = null;
        this._probeAttempts = 0;

        if (this._probeTimeout) {
            clearTimeout(this._probeTimeout);
            this._probeTimeout = null;
        }

        this._emitter.emit(TransmuxingEvents.BUFFERING_END);

        // Fallback: just start from beginning
        this._internalAbort();
        this._remuxer.seek(0);
        this._remuxer.insertDiscontinuity();
        this._loadSegment(this._currentSegmentIndex);
        this._enableStatisticsReporter();
    }

    _enableStatisticsReporter() {
        if (this._statisticsReporter == null) {
            this._statisticsReporter = self.setInterval(
                this._reportStatisticsInfo.bind(this),
            this._config.statisticsInfoReportInterval);
        }
    }

    _disableStatisticsReporter() {
        if (this._statisticsReporter) {
            self.clearInterval(this._statisticsReporter);
            this._statisticsReporter = null;
        }
    }

    _reportSegmentMediaInfo(segmentIndex) {
        let segmentInfo = this._mediaInfo.segments[segmentIndex];
        let exportInfo = Object.assign({}, segmentInfo);

        exportInfo.duration = this._mediaInfo.duration;
        exportInfo.segmentCount = this._mediaInfo.segmentCount;
        delete exportInfo.segments;
        delete exportInfo.keyframesIndex;

        this._emitter.emit(TransmuxingEvents.MEDIA_INFO, exportInfo);
    }

    _reportStatisticsInfo() {
        let info = {};

        info.url = this._ioctl.currentURL;
        info.hasRedirect = this._ioctl.hasRedirect;
        if (info.hasRedirect) {
            info.redirectedURL = this._ioctl.currentRedirectedURL;
        }

        info.speed = this._ioctl.currentSpeed;
        info.loaderType = this._ioctl.loaderType;
        info.currentSegmentIndex = this._currentSegmentIndex;
        info.totalSegmentCount = this._mediaDataSource.segments.length;

        this._emitter.emit(TransmuxingEvents.STATISTICS_INFO, info);
    }

}

export default TransmuxingController;
